<template>
  <div class="advanced-pole-container">
    <div class="control-panel">
      <div class="rotation-controls">
        <div class="axis-control" v-for="axis in axes" :key="axis.name">
          <label :class="{ warning: rotation[axis.name] > 0.5 }">
            {{ axis.label }}: {{ rotation[axis.name] }}°
          </label>
          <input
            type="range"
            :min="axis.min"
            :max="axis.max"
            v-model.number="rotation[axis.name]"
            @input="updatePoleRotation"
          />
          <div class="value-display">
            <button @click="rotation[axis.name] = 0">reset</button>
          </div>
        </div>
      </div>
    </div>

    <!-- 3D场景容器 -->
    <div ref="threeContainer" class="three-scene"></div>

    <!-- 状态信息 -->
    <div class="status-info">
      <div>
        inclination angle: X:{{ rotation.x }}° Y:{{ rotation.y }}° Z:{{
          rotation.z
        }}°
      </div>
    </div>
  </div>
</template>

<script setup>
import { ref, onMounted, onUnmounted, inject, watch } from "vue";
import * as THREE from "three";
import { OrbitControls } from "three/addons/controls/OrbitControls.js";

// 响应式数据
const rotation = ref({ x: 0, y: 0, z: 0 });
const threeContainer = ref(null);
const groundHeight = -7; // 地面高度
const CENTER_POINT = new THREE.Vector3(0, groundHeight, 0);

// 配置数据
const axes = [
  { name: "x", label: "Vertical (X)", min: -30, max: 30 },
  { name: "y", label: "Horizontal (Y)", min: -180, max: 180 },
  { name: "z", label: "Comprehensive", min: -30, max: 30 },
];

// Three.js变量
let scene, camera, renderer, controls, poleGroup, rotationCenter;

onMounted(async () => {
  await initAdvancedScene();
  addRotationCenterMarker();
  animate();
});

onUnmounted(() => {
  if (renderer) {
    renderer.dispose();
  }
});

// 初始化场景
const initAdvancedScene = async () => {
  // 场景设置
  scene = new THREE.Scene();
  scene.background = new THREE.Color("#ffffff");

  // 相机设置
  camera = new THREE.PerspectiveCamera(
    60,
    threeContainer.value.clientWidth / threeContainer.value.clientHeight,
    1,
    100
  );
  camera.position.set(8, 6, 8);
  camera.lookAt(0, groundHeight, 0);

  // 渲染器设置
  renderer = new THREE.WebGLRenderer({
    antialias: true,
    alpha: true,
  });
  renderer.setSize(
    threeContainer.value.clientWidth,
    threeContainer.value.clientHeight
  );
  renderer.shadowMap.enabled = true;
  renderer.shadowMap.type = THREE.PCFSoftShadowMap;
  threeContainer.value.appendChild(renderer.domElement);

  // 控制器
  controls = new OrbitControls(camera, renderer.domElement);
  controls.enableDamping = true;

  // 添加环境
  await setupEnvironment();

  // 创建电线杆
  createAdvancedPole();

  // 添加坐标轴辅助
  // const axesHelper = new THREE.AxesHelper(10);
  // axesHelper.position.copy(CENTER_POINT);
  // scene.add(axesHelper);

  // 窗口调整
  window.addEventListener("resize", onWindowResize);
};

// 添加旋转中心标记
const addRotationCenterMarker = () => {
  // 创建一个小球标记旋转中心
  const markerGeometry = new THREE.SphereGeometry(0.2, 16, 16);
  const markerMaterial = new THREE.MeshBasicMaterial({
    color: 0xff0000,
    transparent: true,
    opacity: 0.7,
  });
  rotationCenter = new THREE.Mesh(markerGeometry, markerMaterial);
  rotationCenter.position.copy(CENTER_POINT);
  scene.add(rotationCenter);

  // 添加坐标线
  const lineMaterial = new THREE.LineDashedMaterial({
    color: 0xff0000,
    dashSize: 0.2, // 虚线段的长度
    gapSize: 0.1, // 间隙的长度
    transparent: true, // 启用透明
    opacity: 0.6, // 透明度 (0-1)
  });

  // X轴方向线
  const xPoints = [
    new THREE.Vector3(-2, groundHeight, 0),
    new THREE.Vector3(2, groundHeight, 0),
  ];
  const xGeometry = new THREE.BufferGeometry().setFromPoints(xPoints);
  const xLine = new THREE.Line(xGeometry, lineMaterial);
  xLine.computeLineDistances();
  scene.add(xLine);

  // Y轴方向线
  const yPoints = [
    new THREE.Vector3(0, groundHeight - 2, 0),
    new THREE.Vector3(0, groundHeight + 13, 0),
  ];
  const yGeometry = new THREE.BufferGeometry().setFromPoints(yPoints);
  const yLine = new THREE.Line(yGeometry, lineMaterial);
  yLine.computeLineDistances();
  scene.add(yLine);

  // Z轴方向线
  const zPoints = [
    new THREE.Vector3(0, groundHeight, -2),
    new THREE.Vector3(0, groundHeight, 2),
  ];
  const zGeometry = new THREE.BufferGeometry().setFromPoints(zPoints);
  const zLine = new THREE.Line(zGeometry, lineMaterial);
  zLine.computeLineDistances();
  scene.add(zLine);
};

// 设置环境
const setupEnvironment = async () => {
  // 高级光照
  const ambientLight = new THREE.AmbientLight(0x404040, 0.4);
  scene.add(ambientLight);

  const directionalLight = new THREE.DirectionalLight(0xffffff, 0.8);
  directionalLight.position.set(10, 15, 10);
  directionalLight.castShadow = true;
  directionalLight.shadow.mapSize.width = 2048;
  directionalLight.shadow.mapSize.height = 2048;
  scene.add(directionalLight);

  // 地面
  const ground = createSimpleCompassGround();
  scene.add(ground);

  // 添加网格辅助
  //   const gridHelper = new THREE.GridHelper(50, 50, 0x444444, 0x222222);
  //   scene.add(gridHelper);
};

// 简洁版圆形地面带方向标识
const createSimpleCompassGround = () => {
  const groundGroup = new THREE.Group();

  // 圆形地面
  const groundGeometry = new THREE.CircleGeometry(4, 32);
  const groundMaterial = new THREE.MeshLambertMaterial({
    color: 0x3cb371,
    side: THREE.DoubleSide,
  });
  const ground = new THREE.Mesh(groundGeometry, groundMaterial);
  ground.rotation.x = -Math.PI / 2;
  ground.receiveShadow = true;
  ground.position.copy(CENTER_POINT);
  groundGroup.add(ground);

  // 添加方向线
  const lineMaterial = new THREE.LineBasicMaterial({ color: 0x1e5c3a });

  // 十字轴线
  const axesPoints = [
    [new THREE.Vector3(0, 0, -4), new THREE.Vector3(0, 0, 4)], // NS
    [new THREE.Vector3(-4, 0, 0), new THREE.Vector3(4, 0, 0)], // EW
  ];

  axesPoints.forEach((points) => {
    const geometry = new THREE.BufferGeometry().setFromPoints(points);
    const line = new THREE.Line(geometry, lineMaterial);
    line.position.copy(CENTER_POINT);
    groundGroup.add(line);
  });

  // 添加方向文字
  const directions = [
    { text: "X", position: new THREE.Vector3(0, 0.1, 3.2) },
    { text: "X", position: new THREE.Vector3(0, 0.1, -3.2) },
    { text: "Y", position: new THREE.Vector3(3.2, 0.1, 0) },
    { text: "Y", position: new THREE.Vector3(-3.2, 0.1, 0) },
  ];

  directions.forEach((dir) => {
    const canvas = document.createElement("canvas");
    canvas.width = 64;
    canvas.height = 32;
    const context = canvas.getContext("2d");

    context.fillStyle = "#1e5c3a";
    context.font = "bold 20px Arial";
    context.textAlign = "center";
    context.textBaseline = "middle";
    context.fillText(dir.text, 32, 16);

    const texture = new THREE.CanvasTexture(canvas);
    const material = new THREE.SpriteMaterial({
      map: texture,
      transparent: true,
    });
    const sprite = new THREE.Sprite(material);
    sprite.position.copy(dir.position);
    sprite.scale.set(0.8, 0.4, 1);
    groundGroup.add(sprite);
  });

  scene.add(groundGroup);
  return groundGroup;
};

// 创建带东南西北标识的圆形地面
const createCompassGround = () => {
  const groundGroup = new THREE.Group();

  // 圆形地面
  const groundGeometry = new THREE.CircleGeometry(4, 32);
  const groundMaterial = new THREE.MeshLambertMaterial({
    color: 0x3cb371,
    side: THREE.DoubleSide,
  });
  const ground = new THREE.Mesh(groundGeometry, groundMaterial);
  ground.rotation.x = -Math.PI / 2;
  ground.receiveShadow = true;
  ground.position.copy(CENTER_POINT);
  groundGroup.add(ground);

  // 添加同心圆网格线
  const circleLinesMaterial = new THREE.LineBasicMaterial({
    color: 0x2e8b57,
    transparent: true,
    opacity: 0.6,
  });

  // 绘制同心圆
  const radii = [1, 2, 3, 4];
  radii.forEach((radius) => {
    const circleGeometry = new THREE.RingGeometry(
      radius - 0.02,
      radius + 0.02,
      64
    );
    const circle = new THREE.Mesh(circleGeometry, groundMaterial);
    circle.rotation.x = -Math.PI / 2;
    circle.position.copy(CENTER_POINT);
    groundGroup.add(circle);

    const lineGeometry = new THREE.BufferGeometry();
    const points = [];
    const segments = 32;
    for (let i = 0; i <= segments; i++) {
      const angle = (i / segments) * Math.PI * 2;
      points.push(
        new THREE.Vector3(Math.cos(angle) * radius, 0, Math.sin(angle) * radius)
      );
    }
    lineGeometry.setFromPoints(points);
    const circleLine = new THREE.Line(lineGeometry, circleLinesMaterial);
    circleLine.position.copy(CENTER_POINT);
    groundGroup.add(circleLine);
  });

  // 添加十字轴线
  const axisLinesMaterial = new THREE.LineBasicMaterial({
    color: 0x1e5c3a,
    linewidth: 2,
  });

  // 南北线 (Z轴)
  const northSouthPoints = [
    new THREE.Vector3(0, 0, -4),
    new THREE.Vector3(0, 0, 4),
  ];
  const northSouthGeometry = new THREE.BufferGeometry().setFromPoints(
    northSouthPoints
  );
  const northSouthLine = new THREE.Line(northSouthGeometry, axisLinesMaterial);
  northSouthLine.position.copy(CENTER_POINT);
  groundGroup.add(northSouthLine);

  // 东西线 (X轴)
  const eastWestPoints = [
    new THREE.Vector3(-4, 0, 0),
    new THREE.Vector3(4, 0, 0),
  ];
  const eastWestGeometry = new THREE.BufferGeometry().setFromPoints(
    eastWestPoints
  );
  const eastWestLine = new THREE.Line(eastWestGeometry, axisLinesMaterial);
  eastWestLine.position.copy(CENTER_POINT);
  groundGroup.add(eastWestLine);

  // 添加方向标识
  const createDirectionMarker = (text, position, rotation) => {
    // 创建文字canvas
    const canvas = document.createElement("canvas");
    canvas.width = 128;
    canvas.height = 64;
    const context = canvas.getContext("2d");

    context.fillStyle = "#1e5c3a";
    context.font = "bold 24px Arial";
    context.textAlign = "center";
    context.textBaseline = "middle";
    context.fillText(text, 64, 32);

    const texture = new THREE.CanvasTexture(canvas);
    const material = new THREE.SpriteMaterial({
      map: texture,
      transparent: true,
    });
    const sprite = new THREE.Sprite(material);
    sprite.position.set(position.x, 0.1, position.z);
    sprite.scale.set(1, 0.5, 1);
    groundGroup.add(sprite);

    // 添加方向箭头
    const arrowGeometry = new THREE.ConeGeometry(0.1, 0.3, 8);
    const arrowMaterial = new THREE.MeshBasicMaterial({ color: 0x1e5c3a });
    const arrow = new THREE.Mesh(arrowGeometry, arrowMaterial);
    arrow.position.set(position.x * 0.7, 0.05, position.z * 0.7);
    arrow.rotation.x = Math.PI / 2;
    arrow.rotation.y = rotation;
    groundGroup.add(arrow);
  };

  // 添加四个主要方向标识
  createDirectionMarker("北", new THREE.Vector3(0, 0, 3.2), 0);
  createDirectionMarker("南", new THREE.Vector3(0, 0, -3.2), Math.PI);
  createDirectionMarker("东", new THREE.Vector3(3.2, 0, 0), -Math.PI / 2);
  createDirectionMarker("西", new THREE.Vector3(-3.2, 0, 0), Math.PI / 2);

  // 添加次要方向标识
  const createMinorDirection = (text, position) => {
    const canvas = document.createElement("canvas");
    canvas.width = 96;
    canvas.height = 32;
    const context = canvas.getContext("2d");

    context.fillStyle = "#2e8b57";
    context.font = "16px Arial";
    context.textAlign = "center";
    context.textBaseline = "middle";
    context.fillText(text, 48, 16);

    const texture = new THREE.CanvasTexture(canvas);
    const material = new THREE.SpriteMaterial({
      map: texture,
      transparent: true,
    });
    const sprite = new THREE.Sprite(material);
    sprite.position.set(position.x, 0.1, position.z);
    sprite.scale.set(0.6, 0.3, 1);
    groundGroup.add(sprite);
  };

  // 添加东北、西北、东南、西南标识
  const angle = Math.PI / 4;
  const minorRadius = 2.8;
  createMinorDirection(
    "东北",
    new THREE.Vector3(
      Math.sin(angle) * minorRadius,
      0,
      Math.cos(angle) * minorRadius
    ),
    -angle
  );

  createMinorDirection(
    "西北",
    new THREE.Vector3(
      Math.sin(-angle) * minorRadius,
      0,
      Math.cos(-angle) * minorRadius
    ),
    angle
  );

  createMinorDirection(
    "东南",
    new THREE.Vector3(
      Math.sin(angle) * minorRadius,
      0,
      Math.cos(-angle) * minorRadius
    ),
    angle + Math.PI
  );

  createMinorDirection(
    "西南",
    new THREE.Vector3(
      Math.sin(-angle) * minorRadius,
      0,
      Math.cos(-angle) * minorRadius
    ),
    -angle + Math.PI
  );

  // 添加刻度标记
  const createTickMark = (angle, length) => {
    const start = new THREE.Vector3(
      Math.sin(angle) * 3.9,
      0,
      Math.cos(angle) * 3.9
    );
    const end = new THREE.Vector3(
      Math.sin(angle) * (3.9 + length),
      0,
      Math.cos(angle) * (3.9 + length)
    );

    const geometry = new THREE.BufferGeometry().setFromPoints([start, end]);
    const material = new THREE.LineBasicMaterial({
      color: 0x1e5c3a,
      transparent: true,
      opacity: 0.8,
    });
    const line = new THREE.Line(geometry, material);
    line.position.copy(CENTER_POINT);
    groundGroup.add(line);
  };

  // 添加主要刻度（每30度）
  for (let i = 0; i < 12; i++) {
    createTickMark((i * Math.PI) / 6, 0.2);
  }

  // 添加次要刻度（每10度）
  for (let i = 0; i < 36; i++) {
    if (i % 3 !== 0) {
      // 跳过主要刻度位置
      createTickMark((i * Math.PI) / 18, 0.1);
    }
  }

  scene.add(groundGroup);
  return groundGroup;
};

// 创建电线杆
const createAdvancedPole = () => {
  poleGroup = new THREE.Group();

  // 电线杆主体
  const poleGeometry = new THREE.CylinderGeometry(0.25, 0.35, 12, 6);

  // 使用更真实的木质材质
  const poleMaterial = new THREE.MeshLambertMaterial({
    color: 0x8b4513,
    // roughness: 0.7,
    // metalness: 0.1,
  });

  const pole = new THREE.Mesh(poleGeometry, poleMaterial);
  pole.castShadow = true;
  pole.receiveShadow = true;
  pole.position.y = 6; // 底部在地面

  // 添加木质纹理细节
  addWoodDetails(pole);

  // 添加电线横担
  addCrossarms();

  // 添加绝缘子串
  addInsulatorStrings();

  poleGroup.add(pole);
  poleGroup.position.copy(CENTER_POINT);
  scene.add(poleGroup);
};

// 添加木质纹理细节
const addWoodDetails = (pole) => {
  // 可以使用法线贴图或细节纹理来增强木质效果
  // 这里简单添加一些环状细节
  const ringGeometry = new THREE.TorusGeometry(0.26, 0.02, 8, 6);
  const ringMaterial = new THREE.MeshLambertMaterial({ color: 0xa0522d });

  for (let i = 0; i < 3; i++) {
    const ring = new THREE.Mesh(ringGeometry, ringMaterial);
    ring.position.y = groundHeight + 8 + i * 2;
    ring.rotation.x = Math.PI / 2;
    ring.rotation.z = Math.PI / 6;
    pole.add(ring);
  }
};

// 添加电线横担
const addCrossarms = () => {
  const crossarmGeometry = new THREE.BoxGeometry(3, 0.1, 0.15);
  const crossarmMaterial = new THREE.MeshLambertMaterial({ color: 0x8b4513 });

  // 在电线杆不同高度添加横担
  const heights = [11, 9, 7]; // 距离地面的高度

  heights.forEach((height) => {
    const crossarm = new THREE.Mesh(crossarmGeometry, crossarmMaterial);
    crossarm.position.y = height;
    crossarm.position.z = 0.2;
    crossarm.castShadow = true;
    poleGroup.add(crossarm);
  });
};

// 添加绝缘子串
const addInsulatorStrings = () => {
  const insulatorGeometry = new THREE.CylinderGeometry(0.08, 0.12, 0.2, 8);
  const insulatorMaterial = new THREE.MeshPhongMaterial({
    color: 0xffffff,
    shininess: 100,
    transparent: true,
    opacity: 0.9,
  });

  // 在每个横担末端添加绝缘子
  for (let i = 0; i < 3; i++) {
    for (let j = -1; j <= 1; j += 2) {
      const insulator = new THREE.Mesh(insulatorGeometry, insulatorMaterial);
      insulator.position.y = 11.15 - i * 2;
      insulator.position.x = j * 1.4;
      insulator.position.z = 0.2;
      insulator.castShadow = true;
      poleGroup.add(insulator);
    }
  }
};

// 更新旋转
const updatePoleRotation = () => {
  if (!poleGroup) return;

  const radX = THREE.MathUtils.degToRad(rotation.value.x);
  const radY = THREE.MathUtils.degToRad(rotation.value.y);
  // const radZ = THREE.MathUtils.degToRad(rotation.value.z);
  const radZ = THREE.MathUtils.degToRad(0); // 目前不考虑Z轴旋转对电线杆的影响

  poleGroup.rotation.set(radX, radZ, radY);
};

const dm = inject("dm");
const { deviceCurrentRotation } = dm;
watch(
  deviceCurrentRotation,
  (newVal) => {
    const [ts, x, y, z] = newVal;
    rotation.value.x = x;
    rotation.value.y = y;
    rotation.value.z = z;
    updatePoleRotation();
  }
  // { deep: true }
);
// 应用预设
const applyPreset = (preset) => {
  rotation.value = { ...preset.rotation };
  updatePoleRotation();
};

// 动画循环
const animate = () => {
  requestAnimationFrame(animate);
  controls.update();
  renderer.render(scene, camera);
};

// 窗口调整
const onWindowResize = () => {
  if (!camera || !renderer) return;

  camera.aspect =
    threeContainer.value.clientWidth / threeContainer.value.clientHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(
    threeContainer.value.clientWidth,
    threeContainer.value.clientHeight
  );
};
</script>

