<template>
  <div>
    <el-card>
      <template #header>
        <div class="info-title">System Status</div>
      </template>
      <el-descriptions :column="2" size="small" border>
        <!-- <template #extra>
          <el-button type="primary">Operation</el-button>
        </template> -->
        <el-descriptions-item>
          <template #label>
            <div class="cell-item">Server state</div>
          </template>
          <el-button
            :type="isConnected ? 'success' : 'danger'"
            size="small"
            @click="open"
          >
            {{ isConnected ? "Connected" : "Disconncted" }}
          </el-button>
        </el-descriptions-item>
        <el-descriptions-item>
          <template #label>
            <div class="cell-item">Lora state</div>
          </template>
          <el-button
            :type="systemStatus.loraConnected ? 'success' : 'danger'"
            size="small"
            @click="connectLora"
          >
            {{ systemStatus.loraConnected ? "Connected" : "Disconncted" }}
          </el-button>
        </el-descriptions-item>
        <el-descriptions-item>
          <template #label>
            <div class="cell-item">Connected ws</div>
          </template>
          {{ systemStatus.connectDeviceNum }}
        </el-descriptions-item>
        <el-descriptions-item>
          <template #label>
            <div class="cell-item">Monitor dev</div>
          </template>
          {{ systemStatus.monitorDeviceNum }}
        </el-descriptions-item>
      </el-descriptions>
    </el-card>
    <el-card>
      <template #header>
        <div class="info-title">Device info</div>
        <br />
        <el-button @click="connectDevice">
          set monitor device id = 3
        </el-button>
        <el-button @click="stopMonitor">stop monitor</el-button>
      </template>
      <div
        v-for="value in deviceProperties"
        :key="value.label"
        style="display: flex; justify-content: space-between; padding: 5px 0"
      >
        <span class="info-label">{{ value.label }}:</span>
        <span>{{ value.value }}</span>
      </div>
      <!-- <template #footer>Footer content</template> -->
    </el-card>
  </div>
</template>
<script setup>
import { computed, inject, onMounted } from "vue";
import { ElMessage, ElMessageBox } from "element-plus";

const dm = inject("dm");
const { deviceInfo, systemStatus } = dm;

const wsm = inject("wsm");
const { isConnected, open } = wsm;

const eb = inject("eb");
const { registHandler } = eb;

const deviceProperties = computed(() => {
  return Object.entries(deviceInfo.value).map(([k, v]) => {
    return { label: k, value: v };
  });
});

const connectLora = () => {
  wsm.send("LORA_CONNECT", {});
};

const connectDevice = () => {
  dm.beginDeviceMonitor(3);
};

const stopMonitor = () => {
  dm.stopDeviceMonitor();
};

onMounted(() => {
  registHandler("LORA_CONNECT", (res) => {
    console.log(res);
    if (res.code == 0) {
      ElMessage({
        type: "success",
        message: res.message,
      });
    } else {
      ElMessageBox.alert(res.message, "Error", {
        confirmButtonText: "OK",
        type: "error",
      });
    }
  });
});
</script>
<style scoped>
.info-title {
  font-size: 18px;
  font-weight: bold;
}
.info-label {
  font-weight: bold;
}
</style>
