import { ElMessage } from "element-plus";
import { ref } from "vue";

export default function eventBus() {
  const eventType = ref(null);
  const eventData = ref(null);
  const eventHandler = ref({});

  const registHandler = (key, handler) => (eventHandler.value[key] = handler);
  const triggerEvent = (eventType, data) => {
    const handler = eventHandler.value[eventType];
    if (handler) handler(data);
    else if (data == "OK") ElMessage.success(eventType + " OK");
  };

  return {
    eventType,
    eventData,
    eventHandler,
    registHandler,
    triggerEvent,
  };
}
