<template>
  <div style="width: 100%; height: 100%" class="box-shadow">
    <div>
      <el-date-picker
        v-model="rrQueryReq.ts_s"
        type="datetime"
        placeholder="Select date and time"
        size="small"
      />
      -
      <el-date-picker
        v-model="rrQueryReq.ts_e"
        type="datetime"
        placeholder="Select date and time"
        size="small"
      />
      <el-button
        type="primary"
        size="small"
        plain
        style="margin-left: 10px"
        @click="rrQuery"
      >
        Query
      </el-button>
    </div>
    <TimeLineChart
      uid="rotation_record"
      :data="chartData"
      :style="{ width: '100%', height: '100%' }"
    />
  </div>
</template>
<script setup>
import { inject, onMounted, reactive, ref, unref, watch } from "vue";

import TimeLineChart from "@/components/TimeLineChart.vue";
import moment from "moment";

const chartReady = ref(false);
const {
  deviceRotationRecords,
  deviceCurrentRotation,
  queryDeviceRotationRecords,
} = inject("dm");
const { registHandler } = inject("eb");
const chartData = ref({
  x: { i: 1, data: [] },
  y: { i: 2, data: [] },
  z: { i: 3, data: [] },
});
const rrQueryReq = reactive({
  ts_s: new Date().setHours(0, 0, 0, 0),
  ts_e: new Date(),
});

const rrQuery = () => {
  queryDeviceRotationRecords({
    ts_s: Math.floor(rrQueryReq.ts_s / 1000),
    ts_e: Math.floor(rrQueryReq.ts_e / 1000),
  });
};
const chartDataUpdate = () => (chartData.value = { ...chartData.value });
const appendChartData = (newData) => {
  newData.forEach((row) => {
    const [ts, x, y, z] = row;
    while (ts < 1000) return;
    const t = moment(Number(ts * 1000)).format("YYYY-MM-DD HH:mm:ss");
    chartData.value.x.data.push({
      name: "x",
      value: [t, x],
    });
    while (chartData.value.x.data.length > 100) chartData.value.x.data.shift();
    chartData.value.y.data.push({
      name: "y",
      value: [t, y],
    });
    while (chartData.value.y.data.length > 100) chartData.value.y.data.shift();
    chartData.value.z.data.push({
      name: "z",
      value: [t, z],
    });
    while (chartData.value.z.data.length > 100) chartData.value.z.data.shift();
  });
};
watch(deviceCurrentRotation, (nv) => {
  if (chartReady.value) {
    appendChartData([nv]);
    chartDataUpdate();
  }
});
onMounted(() => {
  appendChartData(deviceRotationRecords.value);
  chartDataUpdate();
  chartReady.value = true;
  registHandler("DEVICE_RECORDS_UPDATED", (res) => {
    chartData.value.x.data = [];
    chartData.value.y.data = [];
    chartData.value.z.data = [];
    appendChartData(res);
    chartDataUpdate();
  });
});
</script>
<style scoped></style>
