<template>
  <div :id="unionId" />
</template>
<script setup>
import { onMounted, ref, watch, defineProps } from "vue";
import * as echarts from "echarts/core";
import {
  TitleComponent,
  TooltipComponent,
  GridComponent,
  DataZoomComponent,
  LegendComponent,
} from "echarts/components";
import { LineChart } from "echarts/charts";
import { UniversalTransition } from "echarts/features";
import { CanvasRenderer } from "echarts/renderers";
import moment from "moment";

echarts.use([
  TitleComponent,
  TooltipComponent,
  GridComponent,
  LineChart,
  CanvasRenderer,
  UniversalTransition,
  DataZoomComponent,
  LegendComponent,
]);

const props = defineProps({
  uid: { type: String, required: true },
  data: { type: Object, required: true },
  title: String,
  option: Object,
});

const unionId = ref("chart_" + props.uid);
const chartData = ref(props.data);
let chart;
const option = ref({
  title: { text: props.title },
  grid: {
    left: "40",
    right: "60",
    bottom: "40",
    top: "30",
    containLabel: true,
  },
  tooltip: {
    trigger: "axis",
  },
  legend: {
    orient: "vertical",
    right: 10,
    top: 10,
    data: Object.keys(chartData.value),
  },
  xAxis: {
    type: "time",
    axisLabel: {
      rotate: 60,
      formatter: (v) => {
        const time = moment(v);
        return time.minute() + ":" + time.second();
      },
      align: "right",
    },
    name: "time",
  },
  yAxis: {
    name: "value",
  },
  ...props.option,
});
if (option.value.title.subtext != undefined) option.value.grid.top = "90";
const loadSeriesData = () => {
  const series = Object.keys(chartData.value).map((i) => {
    return {
      name: i,
      type: "line",
      showSymbol: false,
      data: chartData.value[i].data,
      lineStyle: {
        width: 1.5,
      },
    };
  });
  return { series };
};

watch(
  () => props.data,
  (nv) => {
    chartData.value = nv;
    chart.setOption(loadSeriesData());
  }
);

onMounted(() => {
  chart = echarts.init(document.getElementById(unionId.value));
  const t = { ...option.value, ...loadSeriesData() };
  chart.setOption(t);
  window.console.log("init chart data");
});
</script>
<style scoped></style>
