import moment from "moment";
import { ref } from "vue";

export default function deviceRepositories(wsm, eb) {
  const deviceInfo = ref({});
  const deviceRotationRecords = ref([]);
  const deviceCurrentRotation = ref([0, 0, 0, 0]);
  const systemStatus = ref({});

  eb.registHandler("QUERY_DEVICE_INFO", (res) => (deviceInfo.value = res));
  eb.registHandler("SYNC_SYSTEM_STATUS", (res) => (systemStatus.value = res));

  eb.registHandler("MONITOR_INCLINATION_RECORD", (res) => {
    if (res.deviceId !== deviceInfo.value.deviceId) return;

    for (let record of res.data) {
      deviceRotationRecords.value.push(record);
    }
    if (res.data.length > 0)
      deviceCurrentRotation.value = res.data[res.data.length - 1];
    else deviceCurrentRotation.value = [0, 0, 0, 0];
    deviceInfo.value["lastUpdate"] = moment().format("YYYY-MM-DD HH:mm:ss");

    while (deviceRotationRecords.value.length > 100) {
      deviceRotationRecords.value.shift();
    }
  });
  eb.registHandler("QUERY_INCLINATION_RECORD", (res) => {
    if (res.deviceId !== deviceInfo.value.deviceId) return;
    deviceRotationRecords.value = [];

    for (let record of res.data) {
      deviceRotationRecords.value.push(record);
    }
    if (res.data.length > 0)
      deviceCurrentRotation.value = res.data[res.data.length - 1];
    else deviceCurrentRotation.value = [0, 0, 0, 0];

    eb.triggerEvent("DEVICE_RECORDS_UPDATED", deviceRotationRecords.value);
  });

  const beginDeviceMonitor = (deviceId) => {
    deviceInfo.value["deviceId"] = deviceId;
    deviceRotationRecords.value = [];
    deviceCurrentRotation.value = [0, 0, 0, 0];
    console.log("beginDeviceMonitor", deviceId);
    wsm.send("QUERY_DEVICE_INFO", { deviceId });
    wsm.send("BEGIN_DEVICE_MONITOR", { deviceId });
  };

  const stopDeviceMonitor = () => {
    wsm.send("STOP_DEVICE_MONITOR", { deviceId: deviceInfo.value.deviceId });
  };

  const queryDeviceRotationRecords = ({ ts_s, ts_e }) => {
    if (!deviceInfo.value.deviceId) return;
    wsm.send("STOP_DEVICE_MONITOR", { deviceId: deviceInfo.value.deviceId });
    wsm.send("QUERY_INCLINATION_RECORD", {
      did: deviceInfo.value.deviceId,
      ts_s,
      ts_e,
    });
  };
  return {
    systemStatus,
    deviceInfo,
    deviceRotationRecords,
    deviceCurrentRotation,

    beginDeviceMonitor,
    stopDeviceMonitor,
    queryDeviceRotationRecords,
  };
}
