import { computed, onBeforeUnmount, ref } from "vue";
import { ElMessage } from "element-plus";

export default function wsServer(eBus) {
  const ws = ref(null);
  const loading = ref(false);

  const open = () => {
    if (ws.value != null) return;
    ws.value = new WebSocket("ws://localhost:9988");
    ws.value.onopen = () => eBus.triggerEvent("WS_OPEN", {});
    ws.value.onmessage = (e) => {
      loading.value = false;
      const data = JSON.parse(e.data.replaceAll("NaN,", "null,"));
      eBus.triggerEvent(data.eventType, data.data);
    };
    ws.value.onclose = () => {
      loading.value = false;
      ws.value = null;
    };
    ws.value.onerror = (e) => {
      loading.value = false;
      console.log("ws onerror", e);
    };
  };

  const close = () => {
    console.log("close");
    if (ws.value) ws.value.close();
    ws.value = null;
  };

  onBeforeUnmount(() => close());

  const send = (eventType, data = {}) => {
    if (ws.value) {
      loading.value = true;
      ws.value.send(JSON.stringify({ eventType, data }));
    } else ElMessage.error("请先连接服务！");
  };

  return {
    loading,
    isConnected: computed(() => ws.value != null),
    send,
    open,
    close,
  };
}
